struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    // Calculate readable size using the size() function
    size_t readable_size = storage.size();

    // Calculate free space using block_size and write_offset
    // Note: Since we don't have direct access to write_offset, we use the relationship
    // between block_size, readable_size, and the fact that readable_size = write_offset - read_offset
    // Free space = total capacity - current write position
    // But we need to account for the fact that write_offset = readable_size + read_offset
    // Since we can't access read_offset directly, we use the known block_size and the fact that
    // the buffer is linear (no wrapping)
    size_t free_space = block_size - (readable_size + storage.read_offset); // This line assumes read_offset is accessible

    // However, the reference materials don't show read_offset as public
    // Alternative approach: use the clear() function behavior to infer
    // Since we can't access private members, we need to use the public interface

    // More accurate approach: use the relationship from the clear() function
    // clear() sets both read and write offsets to 0, so we can calculate
    // free space as total capacity minus the current written data
    // But we don't have a direct way to get write_offset

    // Given the constraints, we'll use the provided size() and the known block_size
    // This is an approximation since we can't access private members
    free_space = block_size - readable_size; // Simplified approach

    return BufferStatus{readable_size, free_space};
}

